-- Extended product planogram tables for Smart Retail testing

CREATE TABLE IF NOT EXISTS shelves (
    shelf_id VARCHAR(50) PRIMARY KEY,
    floor_number INTEGER,
    floor_name VARCHAR(50),
    zone VARCHAR(100),
    aisle VARCHAR(20),
    rack VARCHAR(20),
    bay VARCHAR(20),
    shelf_level INTEGER,
    category_zone VARCHAR(100),
    dominant_subcategory VARCHAR(100),
    max_parts INTEGER,
    products_count INTEGER,
    total_shelf_capacity INTEGER
);

CREATE TABLE IF NOT EXISTS product_planogram (
    id SERIAL PRIMARY KEY,
    barcode VARCHAR(50),
    sku VARCHAR(50),
    brand VARCHAR(100),
    department VARCHAR(100),
    sub_category VARCHAR(100),
    pack_size VARCHAR(50),
    shelf_id VARCHAR(50),
    shelf_part VARCHAR(80),
    position_on_shelf INTEGER,
    facing_count INTEGER,
    shelf_capacity_units INTEGER,
    current_shelf_quantity INTEGER,
    warehouse_quantity INTEGER,
    minimum_shelf_quantity INTEGER,
    max_stock_capacity INTEGER,
    mrp NUMERIC(10,2),
    cost_price NUMERIC(10,2),
    gst_percent NUMERIC(5,2),
    supplier VARCHAR(150),
    movement_class VARCHAR(20),
    avg_daily_sales_units NUMERIC(10,2),
    seasonal_tag VARCHAR(50),
    expiry_required VARCHAR(5),
    expiry_date DATE,
    related_subcategories TEXT,
    planogram_reason TEXT
);
DELETE FROM product_planogram;
DELETE FROM shelves;
